function solve(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);

    // 1. Record original positions and counts for each vowel
    const counts = new Map();
    const firstOccurrence = new Map();
    const vowelIndices = []; // Stores indices of all vowels in s

    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            vowelIndices.push(i);

            // Count
            counts.set(char, (counts.get(char) || 0) + 1);

            // First occurrence
            if (!firstOccurrence.has(char)) {
                firstOccurrence.set(char, i);
            }
        }
    }

    // 2. Prepare the list of vowels to be sorted
    // We need an array of unique vowels present in s.
    const uniqueVowels = Array.from(counts.keys());

    // 3. Define the custom sorting logic
    // Sort criteria:
    // a) Decreasing order of frequency.
    // b) If frequencies are equal, increasing order of first appearance index.
    uniqueVowels.sort((v1, v2) => {
        const freq1 = counts.get(v1);
        const freq2 = counts.get(v2);

        // Compare frequencies (Descending)
        if (freq1 !== freq2) {
            return freq2 - freq1; // freq2 - freq1 for descending order
        }

        // Frequencies are equal, compare first appearance (Ascending)
        const first1 = firstOccurrence.get(v1);
        const first2 = firstOccurrence.get(v2);
        return first1 - first2; // first1 - first2 for ascending order
    });

    // 4. Create the sequence of sorted vowels
    const sortedVowelSequence = [];
    for (const vowel of uniqueVowels) {
        const freq = counts.get(vowel);
        for (let i = 0; i < freq; i++) {
            sortedVowelSequence.push(vowel);
        }
    }

    // 5. Construct the result string
    const result = s.split('');
    let sortedVowelIndex = 0;

    for (const index of vowelIndices) {
        // Replace the original vowel at this index with the next vowel from the sorted sequence
        result[index] = sortedVowelSequence[sortedVowelIndex];
        sortedVowelIndex++;
    }

    return result.join('');
}

